                min_r = min(min_r, r)
                max_r = max(max_r, r)
                min_c = min(min_c, c)
                max_c = max(max_c, c)

    h = max_r - min_r + 1
    w = max_c - min_c + 1
    ch = h // 3
    cw = w // 3

