                                best_score = count
                                best_rect = (sr, sc, er, ec)
                                best_bg = bg_color

    if best_rect is None:
        return grid

    sr, sc, er, ec = best_rect
    oh = er - sr
    ow = ec - sc
    bg = best_bg

    # Find anomalies
    anomalies = []
    fg = None
    for r in range(sr, er):
        for c in range(sc, ec):
            if grid[r][c] != bg:
                anomalies.append((r - sr, c - sc))
                fg = grid[r][c]

