    # Build output with row+col lines through anomaly positions
    output = [[bg]*ow for _ in range(oh)]
    for ar, ac in anomalies:
        for c in range(ow):
            output[ar][c] = fg
        for r in range(oh):
            output[r][ac] = fg

    return output

